import { useEffect, useRef } from "react";

;// CONCATENATED MODULE: external "react"

;// CONCATENATED MODULE: ./src/react/utils.ts

const useFirstMounted = ()=>{
    const ref = useRef(true);
    useEffect(()=>{
        ref.current = false;
    }, []);
    return ref.current;
};

export { useFirstMounted };
